const e=JSON.parse('{"key":"v-4def627a","path":"/%E6%95%B0%E6%8D%AE%E5%BA%93/Redis/%E5%AE%9E%E6%88%98%E7%AF%87/05-%E5%88%86%E5%B8%83%E5%BC%8F%E9%94%81-Redission.html","title":"5 分布式锁-redission","lang":"zh-CN","frontmatter":{"date":"2021-09-10T00:00:00.000Z","category":["Redis"],"tag":["Redis"],"order":5,"description":"5 分布式锁-redission 5.1 分布式锁-redission功能介绍 基于setnx实现的分布式锁存在下面的问题： 不可重入：重入问题是指 获得锁的线程可以再次进入到相同的锁的代码块中，可重入锁的意义在于防止死锁，比如HashTable这样的代码中，他的方法都是使用synchronized修饰的，假如他在一个方法内，调用另一个方法，那么此时如果是不可重入的，不就死锁了吗？所以可重入锁他的主要意义是防止死锁，我们的synchronized和Lock锁都是可重入的。 不可重试：是指目前的分布式只能尝试一次，没有重试机制我们认为合理的情况是：当线程在获得锁失败后，他应该能再次尝试获得锁。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E6%95%B0%E6%8D%AE%E5%BA%93/Redis/%E5%AE%9E%E6%88%98%E7%AF%87/05-%E5%88%86%E5%B8%83%E5%BC%8F%E9%94%81-Redission.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"5 分布式锁-redission"}],["meta",{"property":"og:description","content":"5 分布式锁-redission 5.1 分布式锁-redission功能介绍 基于setnx实现的分布式锁存在下面的问题： 不可重入：重入问题是指 获得锁的线程可以再次进入到相同的锁的代码块中，可重入锁的意义在于防止死锁，比如HashTable这样的代码中，他的方法都是使用synchronized修饰的，假如他在一个方法内，调用另一个方法，那么此时如果是不可重入的，不就死锁了吗？所以可重入锁他的主要意义是防止死锁，我们的synchronized和Lock锁都是可重入的。 不可重试：是指目前的分布式只能尝试一次，没有重试机制我们认为合理的情况是：当线程在获得锁失败后，他应该能再次尝试获得锁。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-11-07T06:21:24.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"Redis"}],["meta",{"property":"article:published_time","content":"2021-09-10T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-11-07T06:21:24.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"5 分布式锁-redission\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2021-09-10T00:00:00.000Z\\",\\"dateModified\\":\\"2023-11-07T06:21:24.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":3,"title":"5.1 分布式锁-redission功能介绍","slug":"_5-1-分布式锁-redission功能介绍","link":"#_5-1-分布式锁-redission功能介绍","children":[]},{"level":3,"title":"5.2 分布式锁-Redission快速入门","slug":"_5-2-分布式锁-redission快速入门","link":"#_5-2-分布式锁-redission快速入门","children":[]},{"level":3,"title":"5.3 分布式锁-redission可重入锁原理","slug":"_5-3-分布式锁-redission可重入锁原理","link":"#_5-3-分布式锁-redission可重入锁原理","children":[]},{"level":3,"title":"5.4 分布式锁-redission锁重试和WatchDog机制","slug":"_5-4-分布式锁-redission锁重试和watchdog机制","link":"#_5-4-分布式锁-redission锁重试和watchdog机制","children":[]},{"level":3,"title":"5.5 分布式锁-redission锁的MutiLock原理","slug":"_5-5-分布式锁-redission锁的mutilock原理","link":"#_5-5-分布式锁-redission锁的mutilock原理","children":[]}],"git":{"createdTime":1699338084000,"updatedTime":1699338084000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":1}]},"readingTime":{"minutes":12.03,"words":3610},"filePathRelative":"数据库/Redis/实战篇/05-分布式锁-Redission.md","localizedDate":"2021年9月10日","excerpt":"<h1> 5 分布式锁-redission</h1>\\n<h3> 5.1 分布式锁-redission功能介绍</h3>\\n<p>基于setnx实现的分布式锁存在下面的问题：</p>\\n<p><strong>不可重入</strong>：重入问题是指 获得锁的线程可以再次进入到相同的锁的代码块中，可重入锁的意义在于防止死锁，比如HashTable这样的代码中，他的方法都是使用synchronized修饰的，假如他在一个方法内，调用另一个方法，那么此时如果是不可重入的，不就死锁了吗？所以可重入锁他的主要意义是防止死锁，我们的synchronized和Lock锁都是可重入的。</p>\\n<p><strong>不可重试</strong>：是指目前的分布式只能尝试一次，没有重试机制我们认为合理的情况是：当线程在获得锁失败后，他应该能再次尝试获得锁。</p>","autoDesc":true}');export{e as data};
